import{_ as a,o,c as e,ag as r}from"./chunks/framework.wqPkq5Rj.js";const h=JSON.parse('{"title":"AI 同事使用指南","description":"","frontmatter":{},"headers":[],"relativePath":"guide/ai-teammates.md","filePath":"guide/ai-teammates.md","lastUpdated":1777169627000}'),p={name:"guide/ai-teammates.md"};function s(n,t,l,i,c,d){return o(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="ai-同事使用指南" tabindex="-1">AI 同事使用指南 <a class="header-anchor" href="#ai-同事使用指南" aria-label="Permalink to &quot;AI 同事使用指南&quot;">​</a></h1><p>你可能已经和 AI 同事聊过几句了。问个问题，得到个回答——挺好的，但其实它能做的远不止这些。</p><p>这篇指南分享几个我们觉得特别好用的方式，你可以挑感兴趣的试试。</p><hr><h2 id="_01-·-先给它一个清晰的角色" tabindex="-1">01 · 先给它一个清晰的角色 <a class="header-anchor" href="#_01-·-先给它一个清晰的角色" aria-label="Permalink to &quot;01 · 先给它一个清晰的角色&quot;">​</a></h2><p>AI 同事刚创建出来的时候，就像一个刚入职但什么都没被交代的新人——它很聪明，但不知道该往哪使劲。</p><p>你可以在它的 <strong>Rules（规则）</strong> 里写几行字，告诉它：你负责什么、产出长什么样。不需要写很多，几句话就够。</p><blockquote><p><strong>举个例子 · Kai 的规则</strong></p><p><code>你是 Kai，团队的深度研究员。</code><code>输出格式：先给结论摘要（3 句话内），再展开分析。</code><code>所有数据必须标注来源链接。</code><code>不确定的信息标注&quot;待验证&quot;。</code></p></blockquote><p>写完之后你会发现，同样是问&quot;帮我分析一下竞品&quot;，Kai 给出来的东西会稳定很多——因为它知道自己该交付什么了。</p><table tabindex="0"><thead><tr><th>AI 同事</th><th>角色定位</th></tr></thead><tbody><tr><td>Kai</td><td>深度研究员——竞品分析、行业调研，产出带来源的结构化报告</td></tr><tr><td>Dana</td><td>内容创作者——推广文案、社交媒体，产出符合品牌调性的即发内容</td></tr></tbody></table><p><strong>怎么设置：</strong> 点击左上方 AI Teammates → 选一个 AI 同事进入它的空间 → 直接跟它说你希望它扮演什么角色，它会自动更新自己的规则。</p><p><img src="https://static.moxtcontent.com/public/resource/ai/gen/56e35c27-a464-45be-9abe-9cd80878c0da.png" alt="AI 同事设置"></p><hr><h2 id="_02-·-把资料放进团队空间" tabindex="-1">02 · 把资料放进团队空间 <a class="header-anchor" href="#_02-·-把资料放进团队空间" aria-label="Permalink to &quot;02 · 把资料放进团队空间&quot;">​</a></h2><p>AI 同事工作的时候，会读取团队空间里的文件。你放进去的产品文档、品牌手册、客户反馈……都会变成它的参考依据。</p><p>这意味着，<strong>你放的资料越多，AI 同事的产出就越贴近你们真实的业务</strong>。</p><blockquote><p>一个直观的对比：</p><p>团队空间里什么都没有时，你让它&quot;写一段产品介绍&quot;——它只能给你一段听起来像模板的通用文案。</p><p>而当你把品牌手册和产品文档放进去之后，同样的请求，它会用你们自己的术语、定位和卖点来写。</p></blockquote><p>如果你觉得 AI 同事的产出&quot;不够懂业务&quot;，先看看团队空间里有没有足够的资料。</p><p><strong>怎么放：</strong> 在左侧「Team space」里新建文件，把内容直接粘贴进去就行。支持 Markdown、CSV 等文本格式，也可以上传 PDF 和图片。如果需要批量导入，点击文件夹旁的 <strong>+</strong> → 「导入」，拖拽上传。</p><hr><h2 id="_03-·-在-slack-里直接-它" tabindex="-1">03 · 在 Slack 里直接 @ 它 <a class="header-anchor" href="#_03-·-在-slack-里直接-它" aria-label="Permalink to &quot;03 · 在 Slack 里直接 @ 它&quot;">​</a></h2><p>你不需要每次都打开 Moxt 才能找 AI 同事。在 Slack 的任意频道里，<strong>@ 它的名字</strong>，它就会参与进来。</p><blockquote><p>比如在 #marketing 频道里：</p><p><code>@Dana 帮忙把这次活动的推文写三个版本，风格分别偏专业、轻松、和好奇心导向</code></p><p>Dana 直接在频道里回复，团队成员可以接着在帖子里讨论和修改。</p></blockquote><p><strong>怎么连接 Slack：</strong> 点击右侧对话界面顶部的 Slack 图标，按弹窗提示完成 OAuth 授权即可。需要管理员权限，如果你不是管理员，找团队里的管理员帮忙操作一次就行。</p><hr><h2 id="_04-·-用-team-skill-统一产出标准" tabindex="-1">04 · 用 Team Skill 统一产出标准 <a class="header-anchor" href="#_04-·-用-team-skill-统一产出标准" aria-label="Permalink to &quot;04 · 用 Team Skill 统一产出标准&quot;">​</a></h2><p>如果你发现团队经常让 AI 同事做类似的事——比如写周报、做竞品对比、整理会议纪要——可以把这些做成 <strong>Team Skill</strong>。</p><p>Skill 就像一套标准化的工作流程。配一次，所有 AI 同事都会按这个格式输出。</p><blockquote><p>几个常见的 Team Skill：</p><p><strong>竞品分析</strong>：输入竞品名称 → 输出标准化对比报告</p><p><strong>会议纪要</strong>：输入会议文字 → 输出结论 + 待办 + 讨论记录</p><p><strong>内容审核</strong>：输入文案 → 检查品牌一致性、语法、敏感词</p></blockquote><p><strong>怎么创建：</strong> 直接跟 AI 同事说&quot;帮我创建一个 Team Skill&quot;，告诉它你想标准化什么任务，它会自动完成配置。</p><hr><h2 id="_05-·-让它自己动起来-定时任务和-webhook" tabindex="-1">05 · 让它自己动起来：定时任务和 Webhook <a class="header-anchor" href="#_05-·-让它自己动起来-定时任务和-webhook" aria-label="Permalink to &quot;05 · 让它自己动起来：定时任务和 Webhook&quot;">​</a></h2><p>AI 同事不一定要等你 @ 它。你可以让它按自己的节奏工作：</p><p><strong>定时任务（Cron）</strong> ——设个时间，它自动做。比如&quot;每周一上午生成上周数据摘要&quot;。</p><p><strong>Webhook</strong> ——外部事件一来，它自动响应。比如&quot;有新的 GitHub Issue，自动生成分析报告&quot;。</p><blockquote><p>Kai 每周五下午自动扫描行业新闻，整理成&quot;本周行业动态&quot;存入团队空间——周一早上打开就能看。</p><p>客户提交了工单 → AI 同事自动分析内容 → 在 Slack #support 频道发通知并建议处理方案。</p></blockquote><p>这些事情一旦跑起来，就不需要人记着去做了。</p><p><strong>怎么设置：</strong> 进入某个 AI 同事的空间，直接跟它说&quot;帮我设置一个定时任务&quot;或&quot;帮我创建一个 Webhook&quot;。AI 同事会自己完成配置。你也可以在左侧 Automation 入口统一管理。</p><p><img src="https://static.moxtcontent.com/public/resource/ai/gen/f22f1a9e-1985-4f1d-8051-ea8252aab8dd.png" alt="自动化设置"></p><hr><h2 id="_06-·-用-heartbeat-帮你盯着" tabindex="-1">06 · 用 Heartbeat 帮你盯着 <a class="header-anchor" href="#_06-·-用-heartbeat-帮你盯着" aria-label="Permalink to &quot;06 · 用 Heartbeat 帮你盯着&quot;">​</a></h2><p>有些事不需要每天做，但需要有人盯着——比如有没有 PR 超时没人 review，竞品文档是不是太久没更新了。</p><p>AI 同事的 <strong>Heartbeat</strong> 就是干这个的。给它一个关注清单，它会定期检查。有情况才通知，没事不打扰。</p><p><strong>怎么设置：</strong> 进入 AI 同事的空间，跟它说&quot;帮我设置 Heartbeat&quot;，然后告诉它你想让它盯什么、多久检查一次、有情况通知到哪里（比如 Slack 频道或 DM）。</p><hr><p>不需要一次全用上。挑一个你觉得最有用的，先让一个 AI 同事把一件事做好——然后再慢慢扩展。</p>',46)])])}const g=a(p,[["render",s]]);export{h as __pageData,g as default};
